import { useState, useEffect } from "react";
import { DARK, LIGHT, Ic, ICONS, Toast } from "./components/UI";
import Home from "./pages/Home";
import Analyzer from "./pages/Analyzer";
import Compliance from "./pages/Compliance";
import Evidence from "./pages/Evidence";
import CaseLaws from "./pages/CaseLaws";
import Footer from "./components/Footer";

// ── Theme ─────────────────────────────────────────────────────────────────────
const T = {
  dark: { ...DARK, amber: "#fbbf24", amberDim: "#2d1f07" },
  light: { ...LIGHT, amber: "#d97706", amberDim: "#fef3c7" },
};

const LINKS = [
  { id: "home", label: "Home", icon: "home" },
  { id: "analyzer", label: "Analyzer", icon: "doc" },
  { id: "compliance", label: "Compliance", icon: "shield" },
  { id: "evidence", label: "Evidence", icon: "camera" },
  { id: "caselaws", label: "Case Laws", icon: "search" },
];

// ── Scales of Justice Logo ────────────────────────────────────────────────────
const ScalesLogo = () => (
  <svg width="22" height="22" viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg">
    {/* Central pillar */}
    <rect x="15" y="3" width="2" height="22" rx="1" fill="white" opacity="0.95" />
    {/* Base */}
    <rect x="8" y="25" width="16" height="2.5" rx="1.25" fill="white" opacity="0.9" />
    {/* Feet */}
    <rect x="6" y="27.5" width="20" height="1.5" rx="0.75" fill="white" opacity="0.7" />
    {/* Horizontal beam */}
    <rect x="4" y="7" width="24" height="2" rx="1" fill="white" opacity="0.95" />
    {/* Top finial */}
    <circle cx="16" cy="4" r="1.8" fill="white" opacity="0.9" />
    {/* Left chain */}
    <line x1="7" y1="9" x2="7" y2="16" stroke="white" strokeWidth="1.3" strokeLinecap="round" opacity="0.8" />
    {/* Right chain */}
    <line x1="25" y1="9" x2="25" y2="16" stroke="white" strokeWidth="1.3" strokeLinecap="round" opacity="0.8" />
    {/* Left pan */}
    <path d="M3.5 16 Q7 21.5 10.5 16" stroke="white" strokeWidth="1.6" strokeLinecap="round" fill="rgba(255,255,255,0.12)" />
    {/* Right pan */}
    <path d="M21.5 16 Q25 21.5 28.5 16" stroke="white" strokeWidth="1.6" strokeLinecap="round" fill="rgba(255,255,255,0.12)" />
    {/* Pan top lines */}
    <line x1="3.5" y1="16" x2="10.5" y2="16" stroke="white" strokeWidth="1" opacity="0.4" />
    <line x1="21.5" y1="16" x2="28.5" y2="16" stroke="white" strokeWidth="1" opacity="0.4" />
  </svg>
);

// ── Nav ───────────────────────────────────────────────────────────────────────
const Nav = ({ page, go, theme, toggle, t }) => {
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 8);
    window.addEventListener("scroll", fn);
    return () => window.removeEventListener("scroll", fn);
  }, []);

  // Close mobile menu on page change
  useEffect(() => { setOpen(false); }, [page]);

  return (
    <>
      <style>{`
        .ns-nav {
          position: fixed; top: 0; left: 0; right: 0; z-index: 1000;
          height: 62px;
          background: ${t.nav};
          backdrop-filter: blur(28px) saturate(200%);
          -webkit-backdrop-filter: blur(28px) saturate(200%);
          border-bottom: 1px solid ${t.border};
          display: flex; align-items: center;
          padding: 0 28px;
          transition: box-shadow 0.25s, border-color 0.25s;
          font-family: 'DM Sans', system-ui, sans-serif;
        }
        .ns-nav.scrolled {
          box-shadow: 0 8px 40px rgba(0,0,0,0.35);
          border-color: ${t.borderHover};
        }

        /* Brand */
        .ns-brand {
          display: flex; align-items: center; gap: 11px;
          cursor: pointer; user-select: none;
          flex-shrink: 0; margin-right: 32px;
          background: none; border: none; padding: 0;
        }
        .ns-logo-box {
          width: 38px; height: 38px; border-radius: 11px;
          background: linear-gradient(148deg, ${t.blue} 0%, #0f2468 100%);
          display: flex; align-items: center; justify-content: center;
          flex-shrink: 0;
          box-shadow: 0 3px 14px ${t.blue}55, inset 0 1px 0 rgba(255,255,255,0.14);
          transition: transform 0.2s, box-shadow 0.2s;
          position: relative; overflow: hidden;
        }
        .ns-logo-box::before {
          content: '';
          position: absolute; inset: 0;
          background: linear-gradient(160deg, rgba(255,255,255,0.1) 0%, transparent 60%);
          border-radius: 11px;
        }
        .ns-brand:hover .ns-logo-box {
          transform: scale(1.06) rotate(-3deg);
          box-shadow: 0 6px 22px ${t.blue}77, inset 0 1px 0 rgba(255,255,255,0.14);
        }
        .ns-brand-col { display: flex; flex-direction: column; gap: 1px; text-align: left; }
        .ns-brand-name {
          font-size: 17px; font-weight: 900; color: ${t.text};
          letter-spacing: -0.04em; line-height: 1.15;
        }
        .ns-brand-accent { color: ${t.blue}; }
        .ns-brand-sub {
          font-size: 8.5px; color: ${t.muted};
          font-weight: 700; letter-spacing: 0.14em; text-transform: uppercase;
        }

        /* Separator */
        .ns-sep {
          width: 1px; height: 24px;
          background: ${t.border};
          margin: 0 24px 0 0; flex-shrink: 0;
        }

        /* Nav links */
        .ns-links { display: flex; align-items: center; gap: 2px; flex: 1; }
        .ns-navbtn {
          display: flex; align-items: center; gap: 6px;
          padding: 6px 13px; border-radius: 9px;
          font-size: 13px; font-weight: 600; color: ${t.sub};
          background: transparent; border: 1px solid transparent;
          cursor: pointer; white-space: nowrap;
          font-family: 'DM Sans', system-ui, sans-serif;
          letter-spacing: -0.01em; transition: all 0.13s;
          position: relative;
        }
        .ns-navbtn:hover  { background: ${t.blue}0a; color: ${t.text}; }
        .ns-navbtn.active {
          background: ${t.blue}18; color: ${t.blue};
          border-color: ${t.blue}40;
        }
        .ns-navbtn.active::after {
          content: ''; position: absolute; bottom: -1px;
          left: 13px; right: 13px; height: 2px;
          background: ${t.blue}; border-radius: 2px 2px 0 0;
        }

        /* Right side */
        .ns-right { display: flex; align-items: center; gap: 8px; flex-shrink: 0; }
        .ns-badge {
          display: flex; align-items: center; gap: 6px;
          padding: 4px 11px; border-radius: 8px;
          background: ${t.blue}16; border: 1px solid ${t.blue}2e;
          font-size: 10px; font-weight: 800; color: ${t.blue};
          letter-spacing: 0.07em; font-family: 'DM Sans', system-ui, sans-serif;
        }
        .ns-dot {
          width: 5px; height: 5px; border-radius: 50%;
          background: ${t.blue}; flex-shrink: 0;
          box-shadow: 0 0 5px ${t.blue};
          animation: nbpulse 2.2s ease-in-out infinite;
        }
        @keyframes nbpulse { 0%,100%{opacity:1} 50%{opacity:0.3} }

        .ns-ibtn {
          width: 34px; height: 34px; border-radius: 8px;
          background: ${t.surfaceUp}; border: 1.5px solid ${t.border};
          cursor: pointer; display: flex; align-items: center;
          justify-content: center; font-size: 14px;
          transition: all 0.14s;
        }
        .ns-ibtn:hover { border-color: ${t.borderHover}; background: ${t.blue}0a; }

        .ns-burger {
          display: none; width: 34px; height: 34px; border-radius: 8px;
          background: none; border: none;
          cursor: pointer; align-items: center; justify-content: center;
          color: ${t.sub}; font-size: 18px; transition: all 0.14s;
          padding: 0;
        }

        /* Mobile drawer */
        .ns-drawer {
          position: fixed; top: 62px; left: 0; right: 0; z-index: 999;
          background: ${t.surface}; border-bottom: 1px solid ${t.border};
          padding: 8px 14px 14px;
          display: flex; flex-direction: column; gap: 2px;
          box-shadow: 0 8px 30px rgba(0,0,0,0.25);
          animation: drawerIn 0.16s ease;
        }
        @keyframes drawerIn { from{opacity:0;transform:translateY(-6px)} to{opacity:1;transform:none} }
        .ns-drawerbtn {
          display: flex; align-items: center; gap: 11px;
          padding: 11px 14px; border-radius: 9px;
          font-size: 14px; font-weight: 600; color: ${t.sub};
          background: transparent; border: none;
          cursor: pointer; text-align: left;
          font-family: 'DM Sans', system-ui, sans-serif;
          transition: all 0.12s;
          width: 100%;
        }
        .ns-drawerbtn:hover  { background: ${t.blue}0a; color: ${t.text}; }
        .ns-drawerbtn.active { background: ${t.blue}18; color: ${t.blue}; }

        @media (max-width: 820px) {
          .ns-links  { display: none !important; }
          .ns-sep    { display: none !important; }
          .ns-badge  { display: none !important; }
          .ns-burger { display: flex !important; }
          .ns-brand  { margin-right: auto !important; }
          .ns-nav    { padding: 0 16px !important; }
        }
      `}</style>

      <nav className={`ns-nav${scrolled ? " scrolled" : ""}`}>

        {/* Brand / Logo */}
        <button className="ns-brand" onClick={() => go("home")}>
          <div className="ns-logo-box">
            <ScalesLogo />
          </div>
          <div className="ns-brand-col">
            <div className="ns-brand-name">
              Nyaya<span className="ns-brand-accent">Setu</span>
            </div>
            <div className="ns-brand-sub">Bridge to Justice</div>
          </div>
        </button>

        <div className="ns-sep" />

        {/* Desktop links */}
        <div className="ns-links">
          {LINKS.map(l => (
            <button
              key={l.id}
              onClick={() => go(l.id)}
              className={`ns-navbtn${page === l.id ? " active" : ""}`}
            >
              <Ic d={ICONS[l.icon]} size={13} color={page === l.id ? t.blue : "inherit"} sw={1.8} />
              {l.label}
            </button>
          ))}
        </div>

        {/* Right controls */}
        <div className="ns-right">
          <div className="ns-badge">
            <div className="ns-dot" />
            BNS 2023
          </div>
          <button className="ns-ibtn" onClick={toggle} title="Toggle theme">
            <Ic d={ICONS[theme === "dark" ? "sun" : "moon"]} size={15} color={t.sub} />
          </button>
          <button
            className="ns-burger"
            onClick={() => setOpen(o => !o)}
          >
            <Ic d={ICONS[open ? "x" : "menu"]} size={20} color={t.sub} />
          </button>
        </div>
      </nav>

      {/* Mobile drawer */}
      {open && (
        <div className="ns-drawer">
          {LINKS.map(l => (
            <button
              key={l.id}
              className={`ns-drawerbtn${page === l.id ? " active" : ""}`}
              onClick={() => { go(l.id); setOpen(false); }}
            >
              <Ic d={ICONS[l.icon]} size={16} color={page === l.id ? t.blue : t.sub} sw={1.8} />
              {l.label}
            </button>
          ))}
        </div>
      )}
    </>
  );
};

// ── App ───────────────────────────────────────────────────────────────────────
function App() {
  const [theme, setTheme] = useState("dark");
  const [page, setPage] = useState("home");
  const [toast, setToast] = useState(null);

  // Persisted state — survives page navigation
  const [analyzerState, setAnalyzerState] = useState({ file: null, result: null, qaHist: [], err: null });
  const [complianceState, setComplianceState] = useState({ text: "", file: null, result: null, mode: "text" });
  const [evidenceState, setEvidenceState] = useState({ file: null, prev: null, cert: null, name: "", brief: "" });
  const [caseLawState, setCaseLawState] = useState({ q: "", results: [], searched: "" });

  const t = T[theme];

  const showToast = (msg, type) => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 4000);
  };

  const pages = {
    home: <Home t={t} go={setPage} />,
    analyzer: <Analyzer t={t} toast={showToast} state={analyzerState} setState={setAnalyzerState} />,
    compliance: <Compliance t={t} toast={showToast} state={complianceState} setState={setComplianceState} />,
    evidence: <Evidence t={t} toast={showToast} state={evidenceState} setState={setEvidenceState} />,
    caselaws: <CaseLaws t={t} toast={showToast} state={caseLawState} setState={setCaseLawState} />,
  };

  return (
    <div style={{
      minHeight: "100vh", background: t.bg, color: t.text,
      fontFamily: "'DM Sans', 'Inter', system-ui, sans-serif",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800;900&family=DM+Serif+Display&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        @keyframes spin    { to { transform: rotate(360deg); } }
        @keyframes fadeUp  { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes slideUp { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes pulse   { 0%,100% { opacity: 1; transform: scale(1); } 50% { opacity: 0.6; transform: scale(0.85); } }
        input:focus, textarea:focus {
          outline: none;
          border-color: ${t.blue} !important;
          box-shadow: 0 0 0 3px ${t.blue}1a !important;
        }
        ::-webkit-scrollbar { width: 5px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: ${t.border}; border-radius: 3px; }
        ::-webkit-scrollbar-thumb:hover { background: ${t.borderHover}; }
        ::selection { background: ${t.blue}44; color: ${t.text}; }
      `}</style>

      <Nav
        page={page} go={setPage}
        theme={theme} toggle={() => setTheme(theme === "dark" ? "light" : "dark")}
        t={t}
      />

      <main style={{ paddingTop: 62 }}>
        {pages[page]}
      </main>

      {page === "home" && <Footer t={t} go={setPage} />}

      {toast && (
        <Toast msg={toast.msg} type={toast.type} t={t} onClose={() => setToast(null)} />
      )}
    </div>
  );
}

export default App;
